import{_ as t,o as a,c as r,a0 as o}from"./chunks/framework.AQcSKqPn.js";const h=JSON.parse('{"title":"雷姆 (Rem)","description":"","frontmatter":{"type":"entity","title":"雷姆 (Rem)","created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","tags":["re-zero","character"],"related":["re-zero-4th-season","subaru-natsuki","authority-of-gluttony"],"sources":["anime/61316.md"],"date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"entities/雷姆-rem.md","filePath":"entities/雷姆-rem.md","lastUpdated":1784010548000}'),i={name:"entities/雷姆-rem.md"};function s(n,e,u,l,d,m){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="雷姆-rem" tabindex="-1">雷姆 (Rem) <a class="header-anchor" href="#雷姆-rem" aria-label="Permalink to &quot;雷姆 (Rem)&quot;">​</a></h1><ul><li><strong>发布日期</strong>: 2026年07月10日 雷姆（Rem）是《Re:Zero kara Hajimeru Isekai Seikatsu》系列的重要角色，鬼族的女仆。</li></ul><h2 id="第四季中的状态" tabindex="-1">第四季中的状态 <a class="header-anchor" href="#第四季中的状态" aria-label="Permalink to &quot;第四季中的状态&quot;">​</a></h2><p>在第四季开始时，雷姆已被&quot;暴食&quot;权能（<a href="/llm-wiki/concepts/暴食权能-authority-of-gluttony">authority-of-gluttony</a>）吞噬，陷入假死状态（suspended animation）。这是驱动本季剧情的关键事件之一。<a href="/llm-wiki/entities/菜月昴-subaru-natsuki">subaru-natsuki</a>寻找解救同伴的方法，很大程度上是为了拯救雷姆。</p><h2 id="剧情意义" tabindex="-1">剧情意义 <a class="header-anchor" href="#剧情意义" aria-label="Permalink to &quot;剧情意义&quot;">​</a></h2><p>雷姆的困境代表了&quot;暴食&quot;权能造成的存在性剥夺——受害者并非死亡，而是其存在被部分或完全抹除。这种状态比死亡更令人绝望，因为它剥夺了受害者被拯救、被记住的可能性。昴的旅程因此具有了双重意义：不仅要恢复雷姆的意识，还要恢复她在世界中的存在。</p>',6)])])}const _=t(i,[["render",s]]);export{h as __pageData,_ as default};
